const offer = ($json.offer || "").toLowerCase();
const promise = ($json.promise || "").toLowerCase();
const pricing = ($json.pricing || "").toLowerCase();
const solution = ($json.solution || "").toLowerCase();
const problem = ($json.problem || "").toLowerCase();

const bannedPatterns = [
  "ai-powered",
  "optimization tool",
  "growth solution",
  "end-to-end",
  "scalable system",
  "streamline",
  "leverage",
  "cutting-edge"
];

let score = 5;

// 1. Check for buzzword density
bannedPatterns.forEach(p => {
  if (offer.includes(p)) score -= 2;
});

// 2. Check for Problem-Offer Grounding (Basic keyword sanity)
// If the problem mentions 'ads' but offer doesn't mention 'ads', 'marketing', or 'campaigns' -> Penalize
const problemKeywords = problem.split(/\s+/).filter(w => w.length > 4);
const hasOverlap = problemKeywords.some(w => offer.includes(w));
if (!hasOverlap) score -= 3;

// 3. Reward specificity & numbers
if (offer.length > 150) score += 1;
if (offer.length < 60) score -= 2; // Too short is probably generic

if (promise.match(/\d+/)) score += 1; // Presence of numbers/timeframes
if (pricing.includes("$")) score += 1;

// 4. Retry handling
const retries = $json.retries || 0;
const forced_accept = retries >= 3;

return [{
  ...$json,
  retries,
  score,
  is_valid: (score >= 4 && retries < 3) || forced_accept,
  forced_accept
}];
